#!/usr/bin/env node
// Explicit holiday data refresh (NOT a build hook).
// Source: NateScarlet/holiday-cn (MIT). Pin with STARLIGHT_HOLIDAY_COMMIT=<sha>
// or let the script resolve the current master SHA once and record it.
//
// Writes src/data/holidays/{year}.json, index.ts, and SOURCE_REVISION.
//
// Usage: npm run fetch:holidays
// Review and commit generated files after refresh.

import { mkdirSync, writeFileSync, existsSync, readdirSync, readFileSync } from 'node:fs';
import { join, dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const ROOT = resolve(dirname(fileURLToPath(import.meta.url)), '..');
const DATA_DIR = join(ROOT, 'src', 'data', 'holidays');

function readPinnedCommit() {
  if (process.env.STARLIGHT_HOLIDAY_COMMIT) {
    return process.env.STARLIGHT_HOLIDAY_COMMIT;
  }
  const revPath = join(DATA_DIR, 'SOURCE_REVISION');
  if (existsSync(revPath)) {
    try {
      const text = readFileSync(revPath, 'utf8');
      const match = text.match(/^commit:\s*([0-9a-f]{7,40})\s*$/im);
      if (match) return match[1];
    } catch {
      /* fall through */
    }
  }
  return null;
}

function writeYear(year, data) {
  mkdirSync(DATA_DIR, { recursive: true });
  writeFileSync(join(DATA_DIR, `${year}.json`), JSON.stringify(data, null, 2) + '\n');
}

function writeSourceRevision(resolvedRef) {
  const lines = [
    '# Holiday data source revision (generated by scripts/fetch-holidays.mjs)',
    '# Do not edit by hand during normal development.',
    'upstream: NateScarlet/holiday-cn',
    `ref: ${resolvedRef}`,
    `fetched_at: ${new Date().toISOString()}`,
    '',
  ];
  if (/^[0-9a-f]{7,40}$/i.test(resolvedRef)) {
    lines.splice(3, 0, `commit: ${resolvedRef}`);
  }
  writeFileSync(join(DATA_DIR, 'SOURCE_REVISION'), lines.join('\n'));
}

function regenerateIndex() {
  const files = readdirSync(DATA_DIR)
    .filter((f) => /^\d{4}\.json$/.test(f))
    .sort();
  const lines = [
    '// AUTO-GENERATED by scripts/fetch-holidays.mjs — DO NOT EDIT',
    '// Refresh explicitly with: npm run fetch:holidays (not a build hook).',
    '',
    "import type { HolidayYear } from '../../utils/holiday';",
    '',
  ];
  const idents = [];
  for (const f of files) {
    const year = f.replace(/\.json$/, '');
    const ident = `y${year}`;
    idents.push(ident);
    lines.push(`import ${ident} from './${f}';`);
  }
  lines.push('');
  lines.push(`export const ALL_HOLIDAYS: HolidayYear[] = [${idents.join(', ')}];`);
  lines.push('');
  writeFileSync(join(DATA_DIR, 'index.ts'), lines.join('\n'));
  console.log(
    `  ✓ 已生成 src/data/holidays/index.ts (含 ${files.length} 个年份: ${files.map((f) => f.replace('.json', '')).join(', ')})`,
  );
}

async function resolvePin() {
  const existing = readPinnedCommit();
  if (existing) return existing;

  if (!process.env.STARLIGHT_HOLIDAY_ALLOW_MASTER) {
    try {
      const res = await fetch(
        'https://api.github.com/repos/NateScarlet/holiday-cn/commits/master',
        {
          headers: {
            Accept: 'application/vnd.github+json',
            'User-Agent': 'starlight-fetch-holidays',
          },
        },
      );
      if (res.ok) {
        const body = await res.json();
        if (body?.sha) {
          console.log(`[fetch-holidays] Resolved master → ${body.sha}`);
          return body.sha;
        }
      }
    } catch (e) {
      console.log(`[fetch-holidays] Could not resolve master SHA (${e.message || e})`);
    }
  }
  return 'master';
}

async function downloadYear(year, pin) {
  const mirrors = [
    (y) => `https://cdn.jsdelivr.net/gh/NateScarlet/holiday-cn@${pin}/${y}.json`,
    (y) => `https://fastly.jsdelivr.net/gh/NateScarlet/holiday-cn@${pin}/${y}.json`,
    (y) => `https://raw.githubusercontent.com/NateScarlet/holiday-cn/${pin}/${y}.json`,
  ];
  for (const buildUrl of mirrors) {
    const url = buildUrl(year);
    try {
      const ac = new AbortController();
      const timer = setTimeout(() => ac.abort(), 15000);
      const res = await fetch(url, { signal: ac.signal });
      clearTimeout(timer);
      if (res.status === 404) {
        console.log(`  ℹ ${year}: ${url} → 404 (尚未发布)`);
        return { status: 'not-found' };
      }
      if (!res.ok) {
        console.log(`  ⚠ ${year}: ${url} → HTTP ${res.status},换下一个镜像`);
        continue;
      }
      const json = await res.json();
      if (!json || !Array.isArray(json.days)) {
        console.log(`  ⚠ ${year}: ${url} → 响应格式异常 (无 days[]),换下一个镜像`);
        continue;
      }
      console.log(`  ✓ ${year}: ${url} (${json.days.length} 条)`);
      return { status: 'ok', data: json };
    } catch (e) {
      console.log(`  ⚠ ${year}: ${url} → ${e.message || e},换下一个镜像`);
    }
  }
  return { status: 'failed' };
}

async function main() {
  const pin = await resolvePin();
  const now = new Date();
  const currentYear = now.getFullYear();
  const nextYear = currentYear + 1;

  console.log(`[fetch-holidays] 目标年份: ${currentYear}, ${nextYear}; pin=${pin}`);
  mkdirSync(DATA_DIR, { recursive: true });

  const [curRes, nextRes] = await Promise.all([
    downloadYear(currentYear, pin),
    downloadYear(nextYear, pin),
  ]);

  if (curRes.status === 'ok') {
    writeYear(currentYear, curRes.data);
  } else if (existsSync(join(DATA_DIR, `${currentYear}.json`))) {
    console.log(`  ℹ ${currentYear}: 下载失败但本地已有快照,沿用旧文件`);
  } else {
    console.log(`  ⚠ ${currentYear}: 下载失败且无本地快照,节假日功能将退化`);
  }

  if (nextRes.status === 'ok') {
    writeYear(nextYear, nextRes.data);
  } else if (nextRes.status === 'not-found') {
    // skip
  } else if (existsSync(join(DATA_DIR, `${nextYear}.json`))) {
    console.log(`  ℹ ${nextYear}: 下载失败但本地已有快照,沿用旧文件`);
  }

  writeSourceRevision(pin);
  regenerateIndex();
  console.log('[fetch-holidays] 完成 — review and commit generated holiday files');
}

main().catch((e) => {
  console.error('[fetch-holidays] 发生异常:', e);
  process.exitCode = 1;
});
